<template>
    <div>
        <div class="container t-mb-5">
            <h4 class="t-text-xl t-font-bold t-mb-5">
                Posts
            </h4>
            <span class="t-text-gray-600 t-text-sm">
                I'm not confident write in english so contents below written in bahasa
            </span>
        </div>
        <ul class="container">
            <div class="t-mb-5">
                <div class="t-flex t-flex-wrap">
                    <TypeSelect @select="(e) => postType = e"  class="t-mr-2" :active="postType == ''"/>
                    <TypeSelect :value="`blog`" :title="`Blog`" @select="(e) => postType = e"  class="t-mr-2" :active="postType == `blog`"/>
                    <TypeSelect :value="`project`" :title="`Project`" @select="(e) => postType = e"  class="t-mr-2" :active="postType == `project`"/>
                </div>
            </div>
            <li v-for="(post, index) in posts" :key="index">
                <router-link 
                    :to="`/posts/${post.id}`"
                    class="t-bg-white t-p-3 t-block t-mb-3 hover:t-no-underline hover:t-text-gray-800 t-shadow-md t-rounded-lg">
                    <h5 class="t-text-gray-500 t-mb-4 t-text-xs">
                        {{post.date}}
                    </h5>
                    <h4 class="t-font-semibold t-mb-1">
                        {{post.title}}
                    </h4>
                    <p class="t-mb-2">
                        {{post.description}}
                    </p>
                    <span class="t-text-xs t-text-gray-600">
                        {{post.type}}
                    </span>
                </router-link>
            </li>
        </ul>
    </div>
</template>
<script>
import TypeSelect from '@/components/TypeSelect.vue';
import axios from 'axios';

export default {
    components: {
        TypeSelect,
    },
    data() {
        return {
            postType: '',
            posts: [],
            originalPost: [],
        }
    },
    watch: {
        postType: function(newVal) {
            const _originalPosts = [...this.originalPosts];
            if(newVal != '' && newVal != null) {
                this.posts = _originalPosts.filter((item) => {
                    return item.type == this.postType
                });
            } else {
                this.posts = _originalPosts;
            }
        }
    },
    methods: {
        async fetchContents() {
            try {
                const response = await axios.get('/contents/data/posts.json');
                this.posts = response.data.data;
                this.originalPosts = [...this.posts];
            } catch(err) {
                console.log(err);
            }
        }   
    },
    mounted() {
        this.fetchContents();
    }
}
</script>